class Solution {
public:
    int minimumChanges(string s, int k) {
        int n = s.size();
        vector<vector<int>> cost(n, vector<int>(n, 0));

        auto minCost = [&](int l, int r) -> int {
            int len = r - l + 1;
            if (len == 1) return 0;
            int res = len;
            for (int d = 1; d < len; ++d) {
                if (len % d) continue;
                int cur = 0;
                for (int i = 0; i < d; ++i) {
                    int left = l + i;
                    int right = l + (len / d - 1) * d + i;
                    while (left < right) {
                        if (s[left] != s[right]) ++cur;
                        left += d;
                        right -= d;
                    }
                }
                res = min(res, cur);
            }
            return res;
        };

        for (int l = 0; l < n; ++l) {
            for (int r = l; r < n; ++r) {
                cost[l][r] = minCost(l, r);
            }
        }

        vector<vector<int>> dp(k + 1, vector<int>(n + 1, 1e9));
        dp[0][0] = 0;
        for (int i = 1; i <= k; ++i) {
            for (int j = 1; j <= n; ++j) {
                for (int p = 0; p < j; ++p) {
                    dp[i][j] = min(dp[i][j], dp[i - 1][p] + cost[p][j - 1]);
                }
            }
        }
        return dp[k][n];
    }
};
